"""
Step ID: step02
Step Name: Compute Effect Sizes (f-squared)
RQ: results/ch6/6.9.5
Generated: 2026-01-19

PURPOSE:
Compute Cohen's f-squared effect sizes for Location x Time interactions via
marginal R-squared comparison (full vs reduced models). Quantifies interaction
strength for both accuracy and confidence measures.

EXPECTED INPUTS:
  - results/ch5/5.5.1/data/step03_theta_scores.csv
    Columns: composite_ID, theta_source, theta_destination, se_source, se_destination
    Expected rows: ~400 (100 UID x 4 tests)

  - results/ch6/6.8.1/data/step03_theta_confidence.csv
    Columns: composite_ID, theta_Source, theta_Destination
    Expected rows: ~400 (100 UID x 4 tests)

EXPECTED OUTPUTS:
  - results/ch6/6.9.5/data/step02_effect_sizes.csv
    Columns: measure, R2_full, R2_reduced, f_squared
    Rows: 3 (accuracy, confidence, difference)
    Validation: R2_full >= R2_reduced, f_squared >= 0

VALIDATION CRITERIA:
  - All 4 models converge successfully
  - R2_full >= R2_reduced for both measures
  - f_squared >= 0 for both measures
  - Expected pattern: f2_accuracy > f2_confidence (dissociation)

g_code REASONING:
- Approach: Reshape WIDE -> LONG, fit full (theta ~ location*TSVR) and reduced
  (theta ~ location+TSVR) models, compute f2 = (R2_full - R2_reduced)/(1 - R2_full)
- Why this approach: f-squared quantifies interaction effect size via marginal R-squared
- Data flow: WIDE theta -> LONG reshape -> 4 LMM fits -> f-squared computation -> CSV
- Expected performance: ~10 minutes (4 LMM fits)

IMPLEMENTATION NOTES:
- Analysis tool: statsmodels.formula.api.mixedlm (direct fitting)
- Validation tool: validate_lmm_convergence from tools.validation
- CRITICAL: Must parse composite_ID to extract UID and test
- CRITICAL: Must add TSVR_hours from test number (T1=0-2, T2=20-32, T3=68-80, T4=140-156)
- Marginal R-squared: proportion of variance explained by fixed effects only
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict
import statsmodels.formula.api as smf

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import validation tool
from tools.validation import validate_lmm_convergence

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step02_compute_effect_sizes.log"

# Input paths
ACCURACY_PATH = PROJECT_ROOT / "results" / "ch5" / "5.5.1" / "data" / "step03_theta_scores.csv"
CONFIDENCE_PATH = PROJECT_ROOT / "results" / "ch6" / "6.8.1" / "data" / "step03_theta_confidence.csv"

# TSVR mapping (test -> hours range midpoint)
TSVR_MAP = {
    # Ch6 confidence format (T1, T2, T3, T4)
    'T1': 1.0,    # 0-2 hours
    'T2': 26.0,   # 20-32 hours
    'T3': 74.0,   # 68-80 hours
    'T4': 148.0,  # 140-156 hours
    # Ch5 accuracy format (1, 2, 3, 4)
    '1': 1.0,
    '2': 26.0,
    '3': 74.0,
    '4': 148.0
}

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Helper Functions
# =============================================================================

def reshape_wide_to_long(df_wide: pd.DataFrame, measure_name: str, theta_col_prefix: str) -> pd.DataFrame:
    """
    Reshape WIDE format (theta_source, theta_destination) to LONG format.

    Input: composite_ID, theta_source, theta_destination
    Output: composite_ID, location, theta (800 rows from 400 rows)
    """
    log(f"[RESHAPE] Converting {measure_name} from WIDE to LONG format...")

    # Parse composite_ID to extract UID and test
    df_wide['UID'] = df_wide['composite_ID'].str.split('_').str[0]
    df_wide['test'] = df_wide['composite_ID'].str.split('_').str[1]

    # Add TSVR_hours
    df_wide['TSVR_hours'] = df_wide['test'].map(TSVR_MAP)

    # Melt to long format
    value_vars_source = [col for col in df_wide.columns if 'source' in col.lower() and 'theta' in col.lower()]
    value_vars_dest = [col for col in df_wide.columns if 'destination' in col.lower() and 'theta' in col.lower()]

    if not value_vars_source or not value_vars_dest:
        raise ValueError(f"Could not find theta_source/theta_destination columns in {measure_name} data")

    theta_source_col = value_vars_source[0]
    theta_dest_col = value_vars_dest[0]

    # Create source rows
    df_source = df_wide[['composite_ID', 'UID', 'test', 'TSVR_hours', theta_source_col]].copy()
    df_source['location'] = 'source'
    df_source['theta'] = df_source[theta_source_col]
    df_source = df_source[['composite_ID', 'UID', 'test', 'TSVR_hours', 'location', 'theta']]

    # Create destination rows
    df_dest = df_wide[['composite_ID', 'UID', 'test', 'TSVR_hours', theta_dest_col]].copy()
    df_dest['location'] = 'destination'
    df_dest['theta'] = df_dest[theta_dest_col]
    df_dest = df_dest[['composite_ID', 'UID', 'test', 'TSVR_hours', 'location', 'theta']]

    # Concatenate
    df_long = pd.concat([df_source, df_dest], ignore_index=True)

    log(f"[RESHAPE] {measure_name}: {len(df_wide)} rows -> {len(df_long)} rows")
    log(f"  Unique UIDs: {df_long['UID'].nunique()}")
    log(f"  Unique locations: {df_long['location'].unique()}")
    log(f"  Unique TSVR values: {sorted(df_long['TSVR_hours'].unique())}")

    return df_long

def compute_marginal_r_squared(lmm_result) -> float:
    """
    Compute marginal R-squared (fixed effects only).

    R2_marginal = Var(fixed effects) / (Var(fixed effects) + Var(random effects) + Var(residual))
    """
    # Get variance of fitted values (fixed effects only)
    fitted_fixed = lmm_result.fittedvalues
    var_fixed = np.var(fitted_fixed)

    # Get residual variance
    var_resid = lmm_result.scale

    # Get random effects variance
    var_random = lmm_result.cov_re.values[0, 0] if hasattr(lmm_result, 'cov_re') else 0

    # Marginal R-squared
    r2_marginal = var_fixed / (var_fixed + var_random + var_resid)

    return r2_marginal

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 2: Compute Effect Sizes (f-squared)")

        # =========================================================================
        # LOAD AND RESHAPE ACCURACY DATA
        # =========================================================================
        log("\n[LOAD 1] Accuracy data")
        df_accuracy_wide = pd.read_csv(ACCURACY_PATH)
        log(f"[LOADED] {ACCURACY_PATH.name} ({len(df_accuracy_wide)} rows)")

        df_accuracy_long = reshape_wide_to_long(df_accuracy_wide, 'accuracy', 'theta')

        # =========================================================================
        # LOAD AND RESHAPE CONFIDENCE DATA
        # =========================================================================
        log("\n[LOAD 2] Confidence data")
        df_confidence_wide = pd.read_csv(CONFIDENCE_PATH)
        log(f"[LOADED] {CONFIDENCE_PATH.name} ({len(df_confidence_wide)} rows)")

        df_confidence_long = reshape_wide_to_long(df_confidence_wide, 'confidence', 'theta')

        # =========================================================================
        # FIT ACCURACY MODELS
        # =========================================================================
        log("\n[FIT 1] Accuracy FULL model (location * TSVR_hours)")
        acc_full = smf.mixedlm(
            formula='theta ~ location * TSVR_hours',
            data=df_accuracy_long,
            groups=df_accuracy_long['UID'],
            re_formula='~1'
        ).fit(reml=False)

        result = validate_lmm_convergence(acc_full)
        if not result['converged']:
            raise ValueError(f"Accuracy FULL model did not converge: {result['message']}")
        log(f"[CONVERGED] Accuracy FULL model")

        log("\n[FIT 2] Accuracy REDUCED model (location + TSVR_hours)")
        acc_reduced = smf.mixedlm(
            formula='theta ~ location + TSVR_hours',
            data=df_accuracy_long,
            groups=df_accuracy_long['UID'],
            re_formula='~1'
        ).fit(reml=False)

        result = validate_lmm_convergence(acc_reduced)
        if not result['converged']:
            raise ValueError(f"Accuracy REDUCED model did not converge: {result['message']}")
        log(f"[CONVERGED] Accuracy REDUCED model")

        # =========================================================================
        # FIT CONFIDENCE MODELS
        # =========================================================================
        log("\n[FIT 3] Confidence FULL model (location * TSVR_hours)")
        conf_full = smf.mixedlm(
            formula='theta ~ location * TSVR_hours',
            data=df_confidence_long,
            groups=df_confidence_long['UID'],
            re_formula='~1'
        ).fit(reml=False)

        result = validate_lmm_convergence(conf_full)
        if not result['converged']:
            raise ValueError(f"Confidence FULL model did not converge: {result['message']}")
        log(f"[CONVERGED] Confidence FULL model")

        log("\n[FIT 4] Confidence REDUCED model (location + TSVR_hours)")
        conf_reduced = smf.mixedlm(
            formula='theta ~ location + TSVR_hours',
            data=df_confidence_long,
            groups=df_confidence_long['UID'],
            re_formula='~1'
        ).fit(reml=False)

        result = validate_lmm_convergence(conf_reduced)
        if not result['converged']:
            raise ValueError(f"Confidence REDUCED model did not converge: {result['message']}")
        log(f"[CONVERGED] Confidence REDUCED model")

        # =========================================================================
        # COMPUTE MARGINAL R-SQUARED
        # =========================================================================
        log("\n[R2] Computing marginal R-squared values")

        r2_acc_full = compute_marginal_r_squared(acc_full)
        r2_acc_reduced = compute_marginal_r_squared(acc_reduced)
        r2_conf_full = compute_marginal_r_squared(conf_full)
        r2_conf_reduced = compute_marginal_r_squared(conf_reduced)

        log(f"[R2] Accuracy: R2_full={r2_acc_full:.4f}, R2_reduced={r2_acc_reduced:.4f}")
        log(f"[R2] Confidence: R2_full={r2_conf_full:.4f}, R2_reduced={r2_conf_reduced:.4f}")

        # =========================================================================
        # COMPUTE f-SQUARED
        # =========================================================================
        log("\n[f2] Computing Cohen's f-squared effect sizes")

        # f2 = (R2_full - R2_reduced) / (1 - R2_full)
        f2_accuracy = (r2_acc_full - r2_acc_reduced) / (1 - r2_acc_full)
        f2_confidence = (r2_conf_full - r2_conf_reduced) / (1 - r2_conf_full)
        delta_f2 = f2_accuracy - f2_confidence

        log(f"[f2] Accuracy: {f2_accuracy:.4f}")
        log(f"[f2] Confidence: {f2_confidence:.4f}")
        log(f"[f2] Delta (accuracy - confidence): {delta_f2:.4f}")

        # =========================================================================
        # CREATE OUTPUT TABLE
        # =========================================================================
        df_effect_sizes = pd.DataFrame([
            {
                'measure': 'accuracy',
                'R2_full': r2_acc_full,
                'R2_reduced': r2_acc_reduced,
                'f_squared': f2_accuracy
            },
            {
                'measure': 'confidence',
                'R2_full': r2_conf_full,
                'R2_reduced': r2_conf_reduced,
                'f_squared': f2_confidence
            },
            {
                'measure': 'difference',
                'R2_full': r2_acc_full - r2_conf_full,
                'R2_reduced': r2_acc_reduced - r2_conf_reduced,
                'f_squared': delta_f2
            }
        ])

        # =========================================================================
        # VALIDATE RESULTS
        # =========================================================================
        log("\n[VALIDATE] Checking f-squared results")

        if r2_acc_full < r2_acc_reduced:
            log(f"[WARN] Accuracy: R2_full < R2_reduced (unexpected)")
        if r2_conf_full < r2_conf_reduced:
            log(f"[WARN] Confidence: R2_full < R2_reduced (unexpected)")

        if f2_accuracy < 0:
            log(f"[WARN] f2_accuracy < 0 (unexpected)")
        if f2_confidence < 0:
            log(f"[WARN] f2_confidence < 0 (unexpected)")

        if f2_accuracy > f2_confidence:
            log(f"[PASS] Expected pattern: f2_accuracy ({f2_accuracy:.4f}) > f2_confidence ({f2_confidence:.4f})")
        else:
            log(f"[WARN] Unexpected pattern: f2_accuracy ({f2_accuracy:.4f}) <= f2_confidence ({f2_confidence:.4f})")

        # =========================================================================
        # SAVE OUTPUT
        # =========================================================================
        output_path = RQ_DIR / "data" / "step02_effect_sizes.csv"
        df_effect_sizes.to_csv(output_path, index=False, encoding='utf-8')
        log(f"\n[SAVE] {output_path.name} ({len(df_effect_sizes)} rows)")

        log("[SUCCESS] Step 2 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
